      "name": "Potion of Poison",
      "details": {
        "aura": "strong conjuration",
        "cl": "12th",
        "slot": "none",
        "type": "cursed",
        "weight": "—",
        "requirements": "any potion",
        "cost": "—",
        "description": "</h3>This potion has lost its beneficial abilities and become a potent\r poison. This poison deals 1d3 Constitution damage per round for 6 rounds. A poisoned creature can make a DC 14 Fortitude\r save each round to negate the damage and end the affliction."
      },
      "link": "http://www.aonprd.com/MagicCursedDisplay.aspx?ItemName=Potion of Poison"
