      "name": "Longarm Bracers",
      "details": {
        "aura": "faint transmutation",
        "cl": "3rd",
        "slot": "wrist",
        "price": "7,200 gp",
        "weight": "1 lb.",
        "requirements": "Craft Wondrous Item, alter self",
        "cost": "3,600 gp",
        "description": "</h3>These bracers are constructed from\r woven strands of bamboo. Three times\r per day, as a swift action, the wearer\r can stretch her arms beyond their limits,\r increasing her reach by 5 feet until the\r start of her next turn. Her weapon attack\r rolls take a –4 penalty, while unarmed\r strikes and natural weapons using the arms take no penalty."
      },
      "link": "http://www.aonprd.com/MagicWondrousDisplay.aspx?FinalName=Longarm Bracers"
